import React, { useState } from "react";
import doctorService from "../../services/doctor.service";

function VideoConsultation() {
  const [createPayload, setCreatePayload] = useState("{}");
  const [joinPayload, setJoinPayload] = useState('{"sessionId":"","doctorId":1}');
  const [endPayload, setEndPayload] = useState('{"sessionId":"","doctorId":1,"consultationNotes":""}');
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const safeParse = (raw) => {
    try {
      return JSON.parse(raw);
    } catch (parseError) {
      throw new Error("Invalid JSON payload");
    }
  };

  const run = async (fn, payloadText) => {
    setError("");
    try {
      const payload = safeParse(payloadText);
      const response = await fn(payload);
      setResult(response.data);
    } catch (err) {
      setError(err.response?.data?.message || err.message || "Request failed");
      setResult(null);
    }
  };

  return (
    <section className="card">
      <h2>Video Consultation</h2>
      <p className="hint">
        Use this panel to call telemedicine endpoints through `doctor_service`.
      </p>

      <label>Create Session Payload</label>
      <textarea value={createPayload} onChange={(e) => setCreatePayload(e.target.value)} rows={5} />
      <button type="button" onClick={() => run(doctorService.createVideoSession, createPayload)}>
        Create Session
      </button>

      <label>Join Session Payload</label>
      <textarea value={joinPayload} onChange={(e) => setJoinPayload(e.target.value)} rows={5} />
      <button type="button" onClick={() => run(doctorService.joinVideoSession, joinPayload)}>
        Join Session
      </button>

      <label>End Session Payload</label>
      <textarea value={endPayload} onChange={(e) => setEndPayload(e.target.value)} rows={5} />
      <button type="button" onClick={() => run(doctorService.endVideoSession, endPayload)}>
        End Session
      </button>

      {error && <p className="error">{error}</p>}
      <pre className="result">{JSON.stringify(result, null, 2)}</pre>
    </section>
  );
}

export default VideoConsultation;
